package org.apache.commons.csv;

import static org.apache.commons.csv.Constants.BACKSPACE;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.END_OF_STREAM;
import static org.apache.commons.csv.Constants.FF;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class LexerReadEscapeTest {

    @Mock
    private ExtendedBufferedReader inMock;

    private Lexer lexer;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        // Create anonymous subclass since Lexer is abstract
        lexer = new Lexer(CSVFormat.DEFAULT, inMock) {
            @Override
            Token nextToken(Token reusableToken) {
                return null;
            }
        };
    }

    @Test
    void testReadEscapeReturnsCR() throws IOException {
        when(inMock.read()).thenReturn((int) 'r');
        int result = lexer.readEscape();
        assertEquals(CR, result);
    }

    @Test
    void testReadEscapeReturnsLF() throws IOException {
        when(inMock.read()).thenReturn((int) 'n');
        int result = lexer.readEscape();
        assertEquals(LF, result);
    }

    @Test
    void testReadEscapeReturnsTAB() throws IOException {
        when(inMock.read()).thenReturn((int) 't');
        int result = lexer.readEscape();
        assertEquals(TAB, result);
    }

    @Test
    void testReadEscapeReturnsBACKSPACE() throws IOException {
        when(inMock.read()).thenReturn((int) 'b');
        int result = lexer.readEscape();
        assertEquals(BACKSPACE, result);
    }

    @Test
    void testReadEscapeReturnsFF() throws IOException {
        when(inMock.read()).thenReturn((int) 'f');
        int result = lexer.readEscape();
        assertEquals(FF, result);
    }

    @Test
    void testReadEscapeReturnsCRChar() throws IOException {
        when(inMock.read()).thenReturn(CR);
        int result = lexer.readEscape();
        assertEquals(CR, result);
    }

    @Test
    void testReadEscapeReturnsLFChar() throws IOException {
        when(inMock.read()).thenReturn(LF);
        int result = lexer.readEscape();
        assertEquals(LF, result);
    }

    @Test
    void testReadEscapeReturnsFFChar() throws IOException {
        when(inMock.read()).thenReturn(FF);
        int result = lexer.readEscape();
        assertEquals(FF, result);
    }

    @Test
    void testReadEscapeReturnsTABChar() throws IOException {
        when(inMock.read()).thenReturn(TAB);
        int result = lexer.readEscape();
        assertEquals(TAB, result);
    }

    @Test
    void testReadEscapeReturnsBACKSPACEChar() throws IOException {
        when(inMock.read()).thenReturn(BACKSPACE);
        int result = lexer.readEscape();
        assertEquals(BACKSPACE, result);
    }

    @Test
    void testReadEscapeThrowsIOExceptionOnEOF() throws IOException {
        when(inMock.read()).thenReturn(END_OF_STREAM);
        IOException thrown = assertThrows(IOException.class, () -> lexer.readEscape());
        assertEquals("EOF whilst processing escape sequence", thrown.getMessage());
    }

    @Test
    void testReadEscapeReturnsDefaultChar() throws IOException {
        int arbitraryChar = 'x';
        when(inMock.read()).thenReturn(arbitraryChar);
        int result = lexer.readEscape();
        assertEquals(arbitraryChar, result);
    }
}
